import{_ as i,o as a,c as n,a2 as t}from"./chunks/framework.BXL42d4u.js";const y=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"VTKFortran","text":"VTK XML API","tagline":"A pure Fortran 2003+ library to parse and emit files conforming the VTK XML standard.","actions":[{"theme":"brand","text":"Guide","link":"/guide/"},{"theme":"alt","text":"API Reference","link":"/api/"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/szaghi/VTKFortran"}]},"features":[{"icon":"📐","title":"VTK XML Support","details":"Write Rectilinear, Structured, and Unstructured grids in the VTK XML format. Composite multi-block datasets (VTM) and parallel partitioned files (PVTS) are also supported."},{"icon":"🗜️","title":"Multiple Output Formats","details":"Choose between ASCII, binary (Base64-encoded), and raw binary appended formats. All procedures return an integer error code for flexible error trapping."},{"icon":"⚡","title":"Parallel Safe","details":"Handle multiple concurrent files safely. Thread and processor safe — works with OpenMP and MPI paradigms without coordination overhead."},{"icon":"🛠️","title":"Multi Build System","details":"Build with CMake (preferred), FoBiS.py, FPM, or GNU Make. Integrate into CMake projects via add_subdirectory and target_link_libraries."},{"icon":"🧱","title":"OOP Design","details":"A polymorphic xml_writer component is allocated at runtime based on the chosen format. The vtk_file, pvtk_file, and vtm_file types expose a clean, consistent type-bound-procedure API."},{"icon":"🆓","title":"Free & Open Source","details":"Multi-licensed — GPLv3 for FOSS projects, BSD 2/3-Clause or MIT for commercial use. Fortran 2003+ standard compliant."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),h={name:"index.md"};function k(l,s,e,p,r,E){return a(),n("div",null,[...s[0]||(s[0]=[t("",11)])])}const g=i(h,[["render",k]]);export{y as __pageData,g as default};
